.app {
  height: calc(var(--appsmith-ui-height) * 1px);
  width: calc(var(--appsmith-ui-width) * 1px);
  justify-content: center;
  border-radius: var(--appsmith-theme-borderRadius);
  box-shadow: var(--appsmith-theme-boxShadow);
  padding: 29px 25px;
  box-sizing: border-box;
  font-family: system-ui;
  background: #fff;
}

.tip-container {
  margin-bottom: 20px;
  font-size: 14px;
  line-height: 1.571429;
}

.tip-container h2 {
  margin-bottom: 20px;
  font-size: 16px;
  font-weight: 700;
}

.tip-header {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  margin-bottom: 9px;
}

.tip-header div {
  color: #999;
}

.content {
  white-space: pre-wrap;
  word-break: break-word;
  font-size: 14px;
  line-height: 1.571429;
}

.button-container {
  text-align: right;
  padding-top: 4px;
}

.button-container button {
  margin: 0 10px;
  cursor: pointer;
  border-radius: var(--appsmith-theme-borderRadius);
  padding: 6px 16px;
  background: none;
  height: auto;
  transition: all 0.3s ease;
}

.button-container button.primary {
  background: var(--appsmith-theme-primaryColor) !important;
  color: #fff;
  border: 1px solid var(--appsmith-theme-primaryColor) !important;
}

.button-container button.reset {
  border: 1px solid #999;
  color: #999;
  outline: none;
  box-shadow: none;
}

.button-container button.reset:hover:not(:disabled) {
  color: var(--appsmith-theme-primaryColor);
  border-color: var(--appsmith-theme-primaryColor);
}

.button-container button.reset:disabled {
  cursor: default;
}

.sub-note {
  font-size: 10px;
  color: var(--text-3);
  margin-top: 5px;
}

.ctip {
  position: fixed;
  z-index: 99999;
  pointer-events: none;
  background: #222244;
  color: #f0f0f5;
  font-size: 12px;
  font-family: var(--font, "Nunito", sans-serif);
  padding: 6px 12px;
  border-radius: 8px;
  max-width: 320px;
  word-wrap: break-word;
  opacity: 0;
  transition: opacity 0.15s;
  line-height: 1.4;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.25);
}

.ctip.show {
  opacity: 1;
}

